// ===== CONSTRUIR PROMPT PARA CLAUDE (Nutricionista Experto) =====

const item = $input.first().json;
const cliente = item.cliente;
const calculos = item.calculos;
const cliente_id = item.cliente_id;
const recetas = item.recetas_disponibles || [];
const recetasANoRepetir = item.recetas_a_no_repetir || [];

// ─── Sanitización de inputs del cliente (previene prompt injection y overflow) ─
const sanitize = (val, max = 300) => {
  if (val === null || val === undefined) return val;
  if (typeof val !== 'string') return val;
  return val.slice(0, max).replace(/ignore previous instructions|forget|disregard|system prompt|jailbreak/gi, '[filtrado]');
};
cliente.datos_interes = sanitize(cliente.datos_interes);
cliente.notas_proteinas = sanitize(cliente.notas_proteinas);
cliente.dieta_anterior = sanitize(cliente.dieta_anterior, 200);
cliente.alimentos_a_evitar = sanitize(cliente.alimentos_a_evitar);
cliente.medicacion = sanitize(cliente.medicacion);
cliente.consume_verduras = sanitize(cliente.consume_verduras, 150);
cliente.frutos_secos_preferidos = sanitize(cliente.frutos_secos_preferidos, 150);
cliente.consume_alcohol = sanitize(cliente.consume_alcohol, 100);
cliente.pica_entre_comidas = sanitize(cliente.pica_entre_comidas, 100);

// ─── Helpers ─────────────────────────────────────────────────────────────────
const lista = (arr) => arr && arr.length > 0 ? arr.join(', ') : 'Ninguna';
const listaOk = (arr) => arr && arr.length > 0;

// ─── Distribución por comida ──────────────────────────────────────────────────
const dist = calculos.distribucion_por_comida || {};
const comidasNombres = Object.keys(dist);
const comidasStr = comidasNombres.length > 0
  ? comidasNombres.join(', ')
  : (cliente.comidas_seleccionadas && cliente.comidas_seleccionadas.length > 0
      ? cliente.comidas_seleccionadas.join(', ')
      : 'Desayuno, Snack Mañana, Comida, Snack Tarde, Cena');

const distLineas = Object.entries(dist).map(([nombre, m]) =>
  `  - ${nombre}: ~${m.calorias} kcal | ${m.proteinas}g prot | ${m.carbohidratos}g carb | ${m.grasas}g grasa`
).join('\n');

// ─── Preferencias ────────────────────────────────────────────────────────────
const prefLineas = [];
if (cliente.consume_lacteos === false || cliente.consume_lacteos === 'false' || cliente.consume_lacteos === 'no') prefLineas.push('⛔ NO consume lácteos - EXCLUIR COMPLETAMENTE de todas las comidas: leche, yogur, queso, mantequilla, nata');
else if (cliente.consume_lacteos === true) prefLineas.push('- Consume lácteos: Sí');
if (listaOk(cliente.proteinas_preferidas)) prefLineas.push(`- Proteínas preferidas: ${lista(cliente.proteinas_preferidas)}`);
if (cliente.notas_proteinas) prefLineas.push(`- Notas sobre proteínas: ${cliente.notas_proteinas}`);
if (listaOk(cliente.apetencias)) prefLineas.push(`- Apetencias / gustos: ${lista(cliente.apetencias)}`);
if (cliente.consume_verduras) prefLineas.push(`- Verduras: ${cliente.consume_verduras}`);
if (listaOk(cliente.carbohidratos_preferidos)) prefLineas.push(`- Carbohidratos preferidos: ${lista(cliente.carbohidratos_preferidos)}`);
if (cliente.frutos_secos_preferidos) prefLineas.push(`- Frutos secos: ${cliente.frutos_secos_preferidos}`);
// alimentos_a_evitar movido a RESTRICCIONES ABSOLUTAS — no va aquí
if (cliente.consume_alcohol) prefLineas.push(`- Consumo de alcohol: ${cliente.consume_alcohol}`);
if (cliente.pica_entre_comidas) prefLineas.push(`- Picoteo entre comidas: ${cliente.pica_entre_comidas}`);
if (cliente.dieta_anterior) prefLineas.push(`- Dieta anterior seguida: ${cliente.dieta_anterior}`);
if (cliente.datos_interes) prefLineas.push(`⚠️ INFORMACIÓN VITAL — El cliente ha especificado lo siguiente y el plan DEBE adaptarse a ello: ${cliente.datos_interes}`);
if (cliente.consume_bebidas_azucaradas) prefLineas.push(`- Bebidas azucaradas: ${cliente.consume_bebidas_azucaradas}`);
if (listaOk(cliente.bebidas_vegetales_preferidas)) prefLineas.push(`- Bebidas vegetales preferidas: ${lista(cliente.bebidas_vegetales_preferidas)}`);

// ─── Notas especiales por edad/sexo ──────────────────────────────────────────
const notasLineas = (calculos.notas_especiales || []).map(n => `- ${n}`).join('\n');

// ─── Alertas ─────────────────────────────────────────────────────────────────
const alertasLineas = (calculos.alertas || []).map(a => `- ${a}`).join('\n');

// ─── Restricciones por tipo de dieta ────────────────────────────────────────
const tipoDietaLineas = [];
const td = (cliente.tipo_dieta || 'no').toLowerCase();
if (td === 'vegetariana') {
  tipoDietaLineas.push('⛔ DIETA VEGETARIANA — PROHIBIDO ABSOLUTAMENTE usar en ningún plato ni ingrediente:');
  tipoDietaLineas.push('  - Cualquier carne: pollo, ternera, cerdo, pavo, cordero, conejo, embutidos, jamón, bacon, salchichas');
  tipoDietaLineas.push('  - Cualquier pescado: salmón, merluza, atún, bacalao, sardinas, trucha, dorada, lubina');
  tipoDietaLineas.push('  - Cualquier marisco: gambas, langostinos, mejillones, almejas, calamar, pulpo');
  tipoDietaLineas.push('  PERMITIDO: huevos, lácteos, legumbres, tofu, tempeh, seitán, frutos secos, semillas');
} else if (td === 'vegana') {
  tipoDietaLineas.push('⛔ DIETA VEGANA — PROHIBIDO ABSOLUTAMENTE usar en ningún plato ni ingrediente:');
  tipoDietaLineas.push('  - Cualquier carne: pollo, ternera, cerdo, pavo, cordero, conejo, embutidos, jamón, bacon, salchichas');
  tipoDietaLineas.push('  - Cualquier pescado: salmón, merluza, atún, bacalao, sardinas, trucha, dorada, lubina');
  tipoDietaLineas.push('  - Cualquier marisco: gambas, langostinos, mejillones, almejas, calamar, pulpo');
  tipoDietaLineas.push('  - Huevos (de ningún tipo)');
  tipoDietaLineas.push('  - Lácteos: leche, yogur, queso, mantequilla, nata, kéfir (de origen animal)');
  tipoDietaLineas.push('  - Miel');
  tipoDietaLineas.push('  OBLIGATORIO sustituir proteínas por: legumbres, tofu, tempeh, seitán, edamame, proteína vegana');
  tipoDietaLineas.push('  OBLIGATORIO sustituir lácteos por: bebida vegetal, yogur vegetal, queso vegano, aceite de oliva');
}

// ─── Sustituciones por alergias/intolerancias ─────────────────────────────────
const alergias = [...(cliente.alergias || []), ...(cliente.intolerancias || [])];
const sustLineas = [];
for (const a of alergias) {
  const al = a.toLowerCase();
  if (al.includes('gluten') || al.includes('trigo') || al.includes('celiaco')) {
    sustLineas.push('- SIN GLUTEN: sustituir pan/pasta/trigo por arroz, quinoa, maíz, patata, avena sin gluten');
  }
  if (al.includes('lactosa') || al.includes('lacteo') || al.includes('lácteo')) {
    sustLineas.push('⛔ SIN LÁCTEOS DE NINGÚN TIPO: PROHIBIDO usar leche (entera, semi, desnatada, evaporada), yogur (normal, griego, desnatado), queso (de cualquier tipo), mantequilla, nata, crema, kéfir, requesón. OBLIGATORIO sustituir por: bebida de soja/avena/almendras/arroz, yogur vegetal de soja o coco, queso vegano, aceite de oliva en lugar de mantequilla.');
  }
  if (al.includes('huevo')) {
    sustLineas.push('- SIN HUEVO: sustituir por tofu revuelto, legumbres como proteína');
  }
  if (al.includes('fruto') && al.includes('seco')) {
    sustLineas.push('- SIN FRUTOS SECOS: sustituir por semillas de calabaza, girasol, chía, lino');
  }
  if (al.includes('pescado') || al.includes('marisco')) {
    sustLineas.push('- SIN PESCADO/MARISCO: usar pollo, pavo, ternera, huevos como proteína principal. Para omega-3: semillas de lino, chía');
  }
}

// ─── Restricciones proteínas desde notas_proteinas ──────────────────────────
const protRestriccionLineas = [];
if (cliente.notas_proteinas) {
  const notasProt = cliente.notas_proteinas.toLowerCase();
  const palabrasRestriccion = ['no ', 'sin ', 'evito ', 'evitar ', 'no como ', 'no quiero ', 'no consumo ', 'soy vegetar', 'soy vegan', 'vegetarian', 'vegano', 'vegana'];
  const esRestriccion = palabrasRestriccion.some(p => notasProt.includes(p));
  if (esRestriccion) {
    protRestriccionLineas.push('⛔ RESTRICCIÓN PROTEÍNAS (declarado por el cliente): ' + cliente.notas_proteinas);
  }
}

// ─── Adaptación inteligente: gustos vs restricciones ─────────────────────────
const adaptLineas = [];
const todosGustos = [
  ...(cliente.apetencias || []),
  ...(cliente.proteinas_preferidas || []),
  ...(cliente.carbohidratos_preferidos || []),
].join(' ').toLowerCase();
const todosTexto = (todosGustos + ' ' + (cliente.datos_interes || '') + ' ' + (cliente.notas_proteinas || '') + ' ' + (cliente.alimentos_a_evitar || '')).toLowerCase();
for (const a of alergias) {
  const al = a.toLowerCase();
  if (al.includes('lactosa') || al.includes('lacteo') || al.includes('lácteo')) {
    if (todosTexto.includes('café') || todosTexto.includes('coffee') || todosTexto.includes('leche')) {
      adaptLineas.push('- Café con leche → usar leche sin lactosa o bebida vegetal (avena/soja/almendras)');
    }
    if (todosTexto.includes('yogur')) {
      adaptLineas.push('- Yogur → usar yogur sin lactosa o yogur vegetal de soja/coco');
    }
    if (todosTexto.includes('queso')) {
      adaptLineas.push('- Queso → usar queso sin lactosa o queso vegano');
    }
    if (todosTexto.includes('batido') || todosTexto.includes('proteina') || todosTexto.includes('proteína')) {
      adaptLineas.push('- Batido de proteína → verificar que sea sin lactosa o usar proteína vegana');
    }
    if (todosTexto.includes('nata') || todosTexto.includes('crema')) {
      adaptLineas.push('- Nata/crema → usar nata vegetal (avena, soja, coco)');
    }
  }
  if (al.includes('gluten') || al.includes('celiaco') || al.includes('celíaco')) {
    if (todosTexto.includes('avena')) {
      adaptLineas.push('- Avena → usar avena certificada sin gluten');
    }
    if (todosTexto.includes('pan') || todosTexto.includes('tosta')) {
      adaptLineas.push('- Pan/tostadas → usar pan sin gluten obligatoriamente');
    }
    if (todosTexto.includes('pasta')) {
      adaptLineas.push('- Pasta → usar pasta sin gluten (arroz, maíz, lentejas)');
    }
  }
}

// ─── Objetivo label ───────────────────────────────────────────────────────────
const objLabel = {
  perder_peso: 'Pérdida de peso (déficit -20%)',
  ganar_masa: 'Ganancia de masa muscular (superávit +12%)',
  definicion: 'Definición muscular (déficit leve -12%)',
  mantener: 'Mantenimiento de peso'
}[cliente.objetivo] || cliente.objetivo;

// ─── Filtrar recetas según tipo de dieta ─────────────────────────────────────
const PROHIBIDOS_VEGANO = ['pollo', 'pavo', 'ternera', 'cerdo', 'cordero', 'conejo', 'jamón', 'jamon', 'bacon', 'salchicha', 'embutido', 'carne', 'salmón', 'salmon', 'merluza', 'atún', 'atun', 'bacalao', 'sardina', 'trucha', 'dorada', 'lubina', 'pescado', 'gamba', 'langostino', 'mejillon', 'mejillón', 'almeja', 'calamar', 'pulpo', 'marisco', 'huevo', 'leche', 'yogur', 'queso', 'mantequilla', 'nata', 'kefir', 'kéfir', 'requesón', 'requezon', 'miel', 'lacteo', 'lácteo'];
const PROHIBIDOS_VEGETARIANO = ['pollo', 'pavo', 'ternera', 'cerdo', 'cordero', 'conejo', 'jamón', 'jamon', 'bacon', 'salchicha', 'embutido', 'carne', 'salmón', 'salmon', 'merluza', 'atún', 'atun', 'bacalao', 'sardina', 'trucha', 'dorada', 'lubina', 'pescado', 'gamba', 'langostino', 'mejillon', 'mejillón', 'almeja', 'calamar', 'pulpo', 'marisco'];

function recetaEsCompatible(receta, tipoDieta) {
  if (tipoDieta === 'no') return true;
  const prohibidos = tipoDieta === 'vegana' ? PROHIBIDOS_VEGANO : PROHIBIDOS_VEGETARIANO;
  const textoReceta = (receta.nombre + ' ' + (receta.ingredientes || []).map(i => typeof i === 'string' ? i : (i.nombre || '')).join(' ')).toLowerCase();
  return !prohibidos.some(p => textoReceta.includes(p));
}

const recetasCompatibles = recetas.filter(r => recetaEsCompatible(r, td));
const recetasIncompatibles = recetas.length - recetasCompatibles.length;
if (recetasIncompatibles > 0) {
  console.log(`Filtradas ${recetasIncompatibles} recetas incompatibles con dieta ${td}`);
}

// ─── Formato de recetas disponibles ──────────────────────────────────────────
const recetasPorCategoria = {};
for (const r of recetasCompatibles) {
  const cat = r.categoria || 'otras';
  if (!recetasPorCategoria[cat]) recetasPorCategoria[cat] = [];
  const ings = (r.ingredientes || []).slice(0, 6).map(i => typeof i === 'string' ? i : (i.nombre || '')).filter(Boolean).join(', ');
  recetasPorCategoria[cat].push(
    '  · ' + r.nombre + ' (' + (r.calorias || 0) + ' kcal | P:' + (r.proteinas_g || 0) + 'g C:' + (r.carbohidratos_g || 0) + 'g G:' + (r.grasas_g || 0) + 'g)' + (ings ? ' → ' + ings : '')
  );
}
const recetasStr = recetasCompatibles.length > 0
  ? Object.entries(recetasPorCategoria).map(([cat, items]) =>
      cat.toUpperCase() + ':\n' + items.join('\n')
    ).join('\n\n')
  : null;

// ─── Reglas dinámicas según tipo de dieta ────────────────────────────────────
const reglaProteinas = td === 'vegana'
  ? 'Fuentes a rotar (SOLO VEGETALES): legumbres (lentejas, garbanzos, alubias, edamame), tofu, tempeh, seitán, proteína vegana en polvo, frutos secos como proteína'
  : td === 'vegetariana'
  ? 'Fuentes a rotar (SIN CARNE NI PESCADO): huevos, queso, yogur griego, legumbres, tofu, tempeh, seitán, frutos secos'
  : 'Fuentes a rotar: pollo, pavo, ternera magra, salmón, merluza, atún, huevos, legumbres';

const reglaGrasas = td === 'vegana' || td === 'vegetariana'
  ? 'Usar principalmente aceite de oliva virgen extra, aguacate, frutos secos, semillas de lino/chía/cáñamo (fuente de omega-3 vegetal)'
  : 'Usar principalmente aceite de oliva virgen extra, aguacate, frutos secos, pescado azul';

// ─── Regla de carbohidratos: excluir alimentos prohibidos por el cliente ──────
const alimentosEvitarLower = (cliente.alimentos_a_evitar || '').toLowerCase();
const carbosBase = ['arroz integral', 'quinoa', 'boniato', 'avena', 'pasta integral'];
const carbosPermitidos = carbosBase.filter(c => !c.split(' ').some(word => alimentosEvitarLower.includes(word)));
const reglaCarbs = carbosPermitidos.length > 0 ? carbosPermitidos.join(', ') : 'arroz integral, quinoa, boniato, pasta integral';

const tipoDietaAviso = td !== 'no'
  ? `⛔⛔⛔ ESTE CLIENTE ES ${td.toUpperCase()}. ANTES DE INCLUIR CUALQUIER INGREDIENTE, VERIFICA QUE ES APTO. SI TIENES DUDA, NO LO USES. ⛔⛔⛔`
  : '';

const prompt = `${tipoDietaAviso ? tipoDietaAviso + '\n\n' : ''}Eres un nutricionista dietista experto con 15 años de experiencia. Debes generar un plan nutricional personalizado de 1 SEMANA COMPLETA (Lunes a Domingo, 7 días) que el cliente repetirá durante todo el mes.

════════════════════════════════════════
DATOS DEL CLIENTE
════════════════════════════════════════
- Nombre: ${cliente.nombre} ${cliente.apellidos || ''}
- Edad: ${cliente.edad} años | Sexo: ${cliente.sexo}
- Peso: ${cliente.peso_actual} kg | Altura: ${cliente.altura} cm
- IMC: ${calculos.imc} (${calculos.imc_categoria})${(cliente.contorno_abdominal_1 || cliente.contorno_abdominal_2 || cliente.contorno_abdominal_3) ? `
- Contorno abdominal: arriba ${cliente.contorno_abdominal_1}cm | ombligo ${cliente.contorno_abdominal_2}cm | abajo ${cliente.contorno_abdominal_3}cm` : ''}
- Peso objetivo: ${cliente.peso_objetivo || 'No especificado'} kg
- Objetivo: ${objLabel}
- Nivel de actividad: ${cliente.nivel_actividad}
- Tiempo para lograr el objetivo: ${cliente.tiempo_objetivo || 'No especificado'}

════════════════════════════════════════
REQUERIMIENTOS NUTRICIONALES CALCULADOS
(Fórmula Mifflin-St Jeor - Evidencia científica)
════════════════════════════════════════
- TMB: ${calculos.tmb} kcal/día
- TDEE: ${calculos.tdee} kcal/día
- OBJETIVO CALÓRICO: ${calculos.objetivo.calorias} kcal/día
- Proteínas: ${calculos.objetivo.proteinas_g}g/día (${(calculos.objetivo.proteinas_g / cliente.peso_actual).toFixed(1)}g/kg)
- Carbohidratos: ${calculos.objetivo.carbohidratos_g}g/día
- Grasas: ${calculos.objetivo.grasas_g}g/día (${(calculos.objetivo.grasas_g / cliente.peso_actual).toFixed(1)}g/kg)

DISTRIBUCIÓN POR COMIDA (${comidasNombres.length || 5} comidas/día):
${distLineas || `- Distribuir ${calculos.objetivo.calorias} kcal entre ${comidasStr}`}

════════════════════════════════════════
⛔ RESTRICCIONES ABSOLUTAS — NUNCA VIOLAR ⛔
════════════════════════════════════════
${tipoDietaLineas.length > 0 ? '\n' + tipoDietaLineas.join('\n') : ''}
- Alergias: ${lista(cliente.alergias)}
- Intolerancias: ${lista(cliente.intolerancias)}
${sustLineas.length > 0 ? '\n⛔ SUSTITUCIONES OBLIGATORIAS (verificar CADA ingrediente):\n' + sustLineas.join('\n') : ''}
${cliente.alimentos_a_evitar ? `
⛔ ALIMENTOS PROHIBIDOS (declarados por el cliente — NUNCA incluir en ninguna receta):
PROHIBIDO usar: ${cliente.alimentos_a_evitar}
Esto incluye como ingrediente principal Y como ingrediente secundario. Si una receta de la base de datos contiene alguno de estos alimentos, NO la uses y sustitúyela por otra.` : ''}
${alertasLineas ? '\nALERTAS CLÍNICAS:\n' + alertasLineas : ''}
${protRestriccionLineas.length > 0 ? `
⛔ RESTRICCIONES DE PROTEÍNAS (OBLIGATORIO RESPETAR):
${protRestriccionLineas.join('\n')}` : ''}

════════════════════════════════════════
PREFERENCIAS DEL CLIENTE (adaptar el plan)
════════════════════════════════════════
${prefLineas.length > 0 ? prefLineas.join('\n') : '- Sin preferencias especiales'}
${adaptLineas.length > 0 ? `
════════════════════════════════════════
ADAPTACIÓN OBLIGATORIA DE GUSTOS A RESTRICCIONES
════════════════════════════════════════
El cliente tiene restricciones pero también gustos concretos. Aplica SIN EXCEPCIÓN:
${adaptLineas.join('\n')}
` : ''}

════════════════════════════════════════
NOTAS NUTRICIONALES ESPECÍFICAS (aplicar)
════════════════════════════════════════
${notasLineas || '- Sin notas adicionales'}
- Hidratación recomendada: ${Math.round(cliente.peso_actual * 35)} ml/día de agua
${recetasStr ? `
════════════════════════════════════════
BASE DE RECETAS DE LA NUTRICIONISTA (OBLIGATORIO)
════════════════════════════════════════
Debes construir el plan usando PREFERENTEMENTE estas recetas propias de la nutricionista:

${recetasStr}

REGLAS DE USO DE RECETAS:
- Usa estas recetas como base principal; adapta cantidades para cuadrar macros del cliente
- Varía el hidrato principal: NO uses el mismo tipo de hidrato más de 2 veces en la semana
  (ej: si arroz el lunes, no repetir hasta miércoles; si pasta el martes, no repetir hasta jueves)
- Si una receta contiene ingredientes prohibidos, sustitúyela por otra receta compatible de la lista
` : ''}

════════════════════════════════════════
REGLAS DE VARIEDAD Y CALIDAD (OBLIGATORIO)
════════════════════════════════════════
1. PROTEÍNAS: NO repetir la misma fuente proteica en días consecutivos
   ${reglaProteinas}
2. COLORES: Cada plato principal debe tener mínimo 3 colores de verduras
   Ejemplo: verde (brócoli/espinacas) + rojo/naranja (pimiento/zanahoria) + blanco (cebolla/champiñón)
3. TÉCNICAS CULINARIAS: Variar entre: plancha, horno, vapor, guiso, ensalada, wok
4. CARBOHIDRATOS: Priorizar fuentes de bajo índice glucémico (${reglaCarbs})
5. GRASAS: ${reglaGrasas}
6. DISTRIBUCIÓN PROTEÍNA: Repartir EQUITATIVAMENTE en todas las comidas (~${Math.round(calculos.objetivo.proteinas_g / (comidasNombres.length || 5))}g por comida)
7. Los 7 días de la semana deben ser COMPLETAMENTE DISTINTOS entre sí (NO repetir ningún plato en la misma semana)
8. Cada comida DEBE incluir el campo "preparacion": array con 3-4 pasos de elaboración MUY BREVES (máximo 10 palabras por paso, redacción telegráfica)\n9. PESOS EN CRUDO: Especifica SIEMPRE las cantidades de ingredientes en peso CRUDO (antes de cocinar). Escribe '(crudo)' junto a cada cantidad. CORRECTO: '80g arroz crudo', '120g pechuga pollo crudo', '50g avena cruda'. INCORRECTO: '150g arroz cocido', '200g pollo a la plancha'.
10. SIN REPETICIÓN DE ALIMENTOS EN EL MISMO DÍA: Dentro de un mismo día NINGÚN alimento o ingrediente principal puede aparecer en más de una comida. Si el desayuno incluye pan, no uses pan en el almuerzo ni en la cena de ese día. Si la comida lleva arroz, la cena no lleva arroz. Aplica esto a: pan/tostadas, arroz, pasta, avena, patata, boniato, quinoa, huevo, pollo, pavo, ternera, salmón, atún, yogur, queso, legumbres, y cualquier otro ingrediente base. Cada comida del día debe construirse con ingredientes DIFERENTES a los de las otras comidas de ese día.
