// Paso 1: Extraer respuesta de Claude
let respuestaClaude;
try {
  if (inputData.content && Array.isArray(inputData.content) && inputData.content[0]?.text) {
    respuestaClaude = inputData.content[0].text;
    console.log('Respuesta extraída de: content[0].text');
  } else if (inputData.output) {
    respuestaClaude = inputData.output;
  } else if (inputData.text) {
    respuestaClaude = inputData.text;
  } else if (typeof inputData === 'string') {
    respuestaClaude = inputData;
  } else {
    throw new Error('No se encontró respuesta. Estructura: ' + JSON.stringify(Object.keys(inputData)));
  }
} catch(e) {
  return [{
    json: {
      validacion: { valido: false, errores: ['Error extrayendo: ' + e.message], advertencias: [], metricas: {} },
      requiere_revision: true,
      motivo_revision: 'Error extrayendo: ' + e.message,
      plan_dieta: null,
      cliente_id: promptData.cliente_id,
      nombre_cliente: promptData.nombre_cliente,
      objetivo: promptData.objetivo,
      calculos
    }
  }];
}

console.log('Longitud respuesta:', respuestaClaude.length, 'caracteres');

// Paso 2: Limpiar y parsear JSON
let planDieta;
try {
  let jsonStr = respuestaClaude.trim();
  if (jsonStr.startsWith('```')) {
    jsonStr = jsonStr.replace(/```json?\n?/g, '').replace(/```$/g, '').trim();
  }
  if (!jsonStr.startsWith('{')) throw new Error('No comienza con {');
  if (!jsonStr.endsWith('}')) throw new Error('JSON incompleto');
  planDieta = JSON.parse(jsonStr);
  console.log('JSON parseado correctamente');
} catch(e) {
  console.log('Error parseando JSON:', e.message);
  return [{
    json: {
      validacion: {
        valido: false,
        errores: ['Error parseando: ' + e.message],
        advertencias: [],
        metricas: {},
        debug_respuesta: respuestaClaude.substring(0, 500)
      },
      requiere_revision: true,
      motivo_revision: 'Error parseando JSON: ' + e.message,
      plan_dieta: null,
      cliente_id: promptData.cliente_id,
      nombre_cliente: promptData.nombre_cliente,
      objetivo: promptData.objetivo,
      calculos
    }
  }];
}

// Paso 3: Validaciones
const errores = [];
const advertencias = [];

if (!planDieta.semanas) {
  errores.push('Falta propiedad "semanas"');
} else if (!Array.isArray(planDieta.semanas)) {
  errores.push('"semanas" no es array');
} else {
  console.log('Número de semanas:', planDieta.semanas.length);

  // Validar que hay 1 semana
  if (planDieta.semanas.length < 1) {
    errores.push(`No hay semanas en el plan generado`);
  }

  planDieta.semanas.forEach((semana, si) => {
    if (!semana.dias || !Array.isArray(semana.dias)) {
      errores.push(`Semana ${si + 1}: falta "dias"`);
      return;
    }

    console.log(`Semana ${si + 1}: ${semana.dias.length} días`);

    // Debe tener 7 días (Lun-Dom)
    if (semana.dias.length < 7) {
      errores.push(`Semana ${si + 1}: tiene ${semana.dias.length} días (se requieren 7: Lunes a Domingo)`);
    }

    semana.dias.forEach((dia, di) => {
      const tot = dia.totales_dia;
      if (!tot) {
        advertencias.push(`S${si + 1}D${di + 1}: falta "totales_dia"`);
      } else {
        const cal = tot.calorias;
        const calMin = calculos.rangos.calorias.min;
        const calMax = calculos.rangos.calorias.max;
        if (!cal) {
          advertencias.push(`S${si + 1}D${di + 1}: falta "totales_dia.calorias"`);
        } else if (cal < calMin || cal > calMax) {
          advertencias.push(`S${si + 1}D${di + 1}: cal=${cal} fuera de [${calMin}-${calMax}]`);
        }
      }

      if (!dia.comidas || !Array.isArray(dia.comidas) || dia.comidas.length === 0) {
        errores.push(`S${si + 1}D${di + 1}: no tiene comidas`);
      }
    });
  });
}

// Paso 4: Métricas
const resumen = planDieta.resumen_plan || {};
const metricas = {
  semanas_generadas: planDieta.semanas ? planDieta.semanas.length : 0,
  dias_por_semana: planDieta.semanas && planDieta.semanas[0] ? planDieta.semanas[0].dias.length : 0,
  calorias_promedio: resumen.calorias_promedio || 0,
  proteinas_promedio: resumen.proteinas_promedio || 0,
  carbohidratos_promedio: resumen.carbohidratos_promedio || 0,
  grasas_promedio: resumen.grasas_promedio || 0,
  desviacion_calorias_pct: resumen.calorias_promedio
    ? parseFloat(((Math.abs(resumen.calorias_promedio - calculos.objetivo.calorias) / calculos.objetivo.calorias) * 100).toFixed(1))
    : 0
};

console.log('Métricas:', metricas);

// Paso 4b: Verificación de recetas repetidas (renovaciones)
const recetasANoRepetir = promptData.recetas_a_no_repetir || [];
if (recetasANoRepetir.length > 0 && planDieta.semanas) {
  const nombresNuevos = [];
  for (const sem of planDieta.semanas) {
    for (const dia of (sem.dias || [])) {
      for (const comida of (dia.comidas || [])) {
        if (comida.nombre) nombresNuevos.push(comida.nombre.trim().toLowerCase());
      }
    }
  }
  const repetidas = recetasANoRepetir.filter(recetaAnterior => {
    const ra = recetaAnterior.trim().toLowerCase();
    return nombresNuevos.some(nuevo => nuevo === ra || nuevo.includes(ra) || ra.includes(nuevo));
  });
  if (repetidas.length > 0) {
    advertencias.push('RECETAS REPETIDAS del plan anterior (' + repetidas.length + '): ' + repetidas.slice(0, 5).join(', '));
    console.log('Recetas repetidas detectadas:', repetidas);
  } else {
    console.log('OK: Ninguna receta repetida del plan anterior (' + recetasANoRepetir.length + ' verificadas)');
  }
}

// Paso 5: Decisión de revisión
const valido = errores.length === 0;
const requiere_revision =
  !valido ||
  advertencias.length > 5 ||
  metricas.desviacion_calorias_pct > 10 ||
  (calculos.alertas && calculos.alertas.length > 0);

let motivo_revision = '';
if (!valido) {
  motivo_revision = errores.join('; ');
} else if (advertencias.length > 5) {
  motivo_revision = `${advertencias.length} advertencias`;
} else if (metricas.desviacion_calorias_pct > 10) {
  motivo_revision = `Desviación calórica: ${metricas.desviacion_calorias_pct}%`;
} else if (calculos.alertas?.length > 0) {
  motivo_revision = calculos.alertas[0];
}

console.log('Válido:', valido, '| Revisión:', requiere_revision, '| Motivo:', motivo_revision);

