// ===== PREPARAR DATOS COMPLETOS PARA CONSTRUIR PROMPT =====

const stripeData = $('Function - Reconstruir Datos tras Pago').first().json;
const recetas = $input.all();
const tipoDieta = (stripeData.cliente.tipo_dieta || 'no').toLowerCase();

// Filtrar recetas incompatibles con el tipo de dieta del cliente
// Primero usa las columnas booleanas (apto_vegano / apto_vegetariano);
// si no están definidas, hace fallback por nombre de ingredientes.
const PROHIBIDOS_VEGANO = ['pollo','pavo','ternera','cerdo','cordero','conejo','jamon','jamón','bacon','salchicha','embutido','carne','salmon','salmón','merluza','atun','atún','bacalao','sardina','trucha','dorada','lubina','pescado','gamba','langostino','mejillon','mejillón','almeja','calamar','pulpo','marisco','huevo','leche','yogur','queso','mantequilla','nata','kefir','kéfir','requezon','requesón','miel'];
const PROHIBIDOS_VEGETARIANO = ['pollo','pavo','ternera','cerdo','cordero','conejo','jamon','jamón','bacon','salchicha','embutido','carne','salmon','salmón','merluza','atun','atún','bacalao','sardina','trucha','dorada','lubina','pescado','gamba','langostino','mejillon','mejillón','almeja','calamar','pulpo','marisco'];

function recetaCompatible(r, td) {
  if (td === 'no') return true;
  // Usar columnas booleanas si están definidas en Supabase
  if (td === 'vegana') {
    if (r.apto_vegano === true) return true;
    if (r.apto_vegano === false) return false;
  }
  if (td === 'vegetariana') {
    if (r.apto_vegetariano === true) return true;
    if (r.apto_vegetariano === false) return false;
  }
  // Fallback: analizar ingredientes por nombre
  const prohibidos = td === 'vegana' ? PROHIBIDOS_VEGANO : PROHIBIDOS_VEGETARIANO;
  const textoReceta = (r.nombre + ' ' + (r.ingredientes || []).map(i => typeof i === 'string' ? i : (i.nombre || '')).join(' ')).toLowerCase();
  return !prohibidos.some(p => textoReceta.includes(p));
}

const recetasCompatibles = recetas.map(r => r.json).filter(r => recetaCompatible(r, tipoDieta));

return [{
  json: {
    cliente_id: stripeData.cliente_id,
    cliente: stripeData.cliente,
    calculos: stripeData.calculos,
    recetas_disponibles: recetasCompatibles,
    metadata: stripeData.metadata,
    es_renovacion: stripeData.es_renovacion || false,
    recetas_a_no_repetir: stripeData.recetas_a_no_repetir || []
  }
}];

// ===== RECONSTRUIR DATOS TRAS PAGO (Reglas Nutricionista Experto) =====
const inputData = $input.first().json;
const c = inputData;

if (!c || !c.id) {
  throw new Error('No se encontró el cliente en Supabase. Datos: ' + JSON.stringify(inputData));
}

// ─── Detección de renovación ─────────────────────────────────────────────────
const stripeEvent = $('Stripe Trigger - Pago Completado').first().json;
const stripeMetadata = stripeEvent?.data?.object?.metadata || {};
const esRenovacion = stripeMetadata.tipo === 'renovacion';

// ─── 1. TMB: Mifflin-St Jeor (más precisa) ───────────────────────────────────
const tmb = c.sexo === 'masculino'
  ? (10 * c.peso_actual) + (6.25 * c.altura) - (5 * c.edad) + 5
  : (10 * c.peso_actual) + (6.25 * c.altura) - (5 * c.edad) - 161;

// ─── 2. TDEE ─────────────────────────────────────────────────────────────────
const factoresActividad = {
  sedentario:      1.2,
  ligero:          1.375,
  moderado:        1.55,
  activo:          1.725,
  muy_activo:      1.9
};
const tdee = tmb * (factoresActividad[c.nivel_actividad] || 1.375);

// ─── 3. Calorías objetivo por objetivo ───────────────────────────────────────
const ajustesCalorias = {
  perder_peso: 0.80,   // -20% déficit
  ganar_masa:  1.12,   // +12% superávit
  definicion:  0.88,   // -12% déficit leve
  mantener:    1.00
};
const cal_objetivo = Math.round(tdee * (ajustesCalorias[c.objetivo] || 1.0));

// ─── 4. Proteínas (reglas nutricionista) ─────────────────────────────────────
// Base por objetivo (g/kg)
const baseProt = {
  perder_peso: 2.2,   // preservar músculo en déficit
  ganar_masa:  1.9,   // construcción muscular
  definicion:  2.4,   // máxima preservación
  mantener:    1.8
};
let factorProt = baseProt[c.objetivo] || 1.8;
// Ajuste por edad (anti-sarcopenia)
if (c.edad >= 60) factorProt += 0.4;
else if (c.edad >= 40) factorProt += 0.2;
const proteinas_g = Math.round(c.peso_actual * factorProt);

// ─── 5. Grasas (reglas por sexo) ─────────────────────────────────────────────
// Mujeres: 1.0 g/kg (NUNCA <0.9 - salud hormonal)
// Hombres: 0.9 g/kg (NUNCA <0.7)
const factorGrasa = c.sexo === 'femenino' ? 1.0 : 0.9;
const grasas_g_calc = Math.round(c.peso_actual * factorGrasa);
const grasas_min = c.sexo === 'femenino'
  ? Math.round(c.peso_actual * 0.9)
  : Math.round(c.peso_actual * 0.7);
const grasas_g = Math.max(grasas_g_calc, grasas_min);

// ─── 6. Carbohidratos (variable de ajuste) ───────────────────────────────────
const cal_prot  = proteinas_g * 4;
const cal_grasa = grasas_g * 9;
const carbos_g  = Math.max(0, Math.round((cal_objetivo - cal_prot - cal_grasa) / 4));

// ─── 7. Distribución por comida ──────────────────────────────────────────────
const numComidas = c.comidas_diarias || 5;
// Usar nombres reales de comidas seleccionadas por el cliente
const comidasActuales = (c.comidas_seleccionadas && c.comidas_seleccionadas.length > 0)
  ? c.comidas_seleccionadas
  : numComidas <= 3 ? ['Desayuno', 'Comida', 'Cena']
  : numComidas === 4 ? ['Desayuno', 'Almuerzo', 'Comida', 'Cena']
  : ['Desayuno', 'Almuerzo', 'Comida', 'Merienda', 'Cena'];

// Porcentaje calórico por tipo de comida
const PCT_COMIDA = {
  'desayuno': 0.25, 'almuerzo': 0.15, 'comida': 0.35,
  'merienda': 0.15, 'cena': 0.25
};
const rawPcts = {};
for (const nombre of comidasActuales) {
  const key = nombre.toLowerCase();
  rawPcts[nombre] = PCT_COMIDA[key] || (key.includes('snack') ? 0.15 : 0.20);
}
const totalPct = Object.values(rawPcts).reduce((a, b) => a + b, 0);
const patronComidas = {};
for (const [n, p] of Object.entries(rawPcts)) {
  patronComidas[n] = p / totalPct;
}
const distribucionComidas = {};
const protPorComida = Math.round(proteinas_g / Object.keys(patronComidas).length);
for (const [nombre, pct] of Object.entries(patronComidas)) {
  const cal = Math.round(cal_objetivo * pct);
  const grasa = Math.round(grasas_g * pct);
  const carb = Math.max(0, Math.round((cal - protPorComida * 4 - grasa * 9) / 4));
  distribucionComidas[nombre] = { calorias: cal, proteinas: protPorComida, grasas: grasa, carbohidratos: carb };
}

// ─── 8. Notas por edad y sexo ────────────────────────────────────────────────
const notasEspeciales = [];
if (c.edad >= 60) {
  notasEspeciales.push('Proteína aumentada para prevenir sarcopenia (pérdida muscular)');
  notasEspeciales.push('Priorizar alimentos ricos en calcio y vitamina D');
  notasEspeciales.push('Texturas más blandas si es necesario');
} else if (c.edad >= 50) {
  notasEspeciales.push('Proteína incrementada para preservar masa muscular');
  notasEspeciales.push('Aumentar omega-3 para salud cardiovascular');
  notasEspeciales.push('Control de sodio (<2300mg/día)');
} else if (c.edad >= 40) {
  notasEspeciales.push('Ligero incremento de proteína por cambios metabólicos');
  notasEspeciales.push('Incluir omega-3 regularmente');
  notasEspeciales.push('Controlar carbohidratos refinados');
}

if (c.sexo === 'femenino') {
  notasEspeciales.push('Grasas mantenidas altas para salud hormonal (nunca <0.9g/kg)');
  notasEspeciales.push('Asegurar hierro: 18mg/día (carnes rojas, legumbres, espinacas)');
  notasEspeciales.push('Calcio: 1000-1200mg/día');
  if (c.edad >= 50) notasEspeciales.push('Post-menopausia: considerar fitoestrógenos (soja, lino)');
} else {
  notasEspeciales.push('Zinc: 11mg/día (producción testosterona: carnes, semillas de calabaza)');
}

// ─── 9. IMC ──────────────────────────────────────────────────────────────────
const imc = c.imc || parseFloat((c.peso_actual / Math.pow(c.altura / 100, 2)).toFixed(1));
const imc_cat = imc < 18.5 ? 'Bajo peso' : imc < 25 ? 'Normal' : imc < 30 ? 'Sobrepeso' : 'Obesidad';

// ─── 10. Alertas ─────────────────────────────────────────────────────────────
const alertas = [];
if (cal_objetivo < 1200) alertas.push('ALERTA: Calorías muy bajas (<1200 kcal). Requiere supervisión.');
if (imc < 17 || imc > 40) alertas.push('ALERTA: IMC extremo. Requiere supervisión médica.');
if (carbos_g < 50) alertas.push('ADVERTENCIA: Carbohidratos muy bajos (<50g). Vigilar energía.');

const rango = (v, p = 0.05) => ({ min: Math.round(v * (1 - p)), max: Math.round(v * (1 + p)) });

return [{
  json: {
    cliente_id: c.id,
    cliente: {
      id: c.id,
      nombre: c.nombre,
      apellidos: c.apellidos || '',
      email: c.email,
      telefono: c.telefono || '',
      edad: c.edad,
      sexo: c.sexo,
      peso_actual: c.peso_actual,
      altura: c.altura,
      peso_objetivo: c.peso_objetivo || null,
      objetivo: c.objetivo,
      tiempo_objetivo: c.tiempo_objetivo || '',
      nivel_actividad: c.nivel_actividad,
      comidas_diarias: numComidas,
      comidas_seleccionadas: c.comidas_seleccionadas || [],
      alergias: c.alergias || [],
      intolerancias: c.intolerancias || [],
      patologias: c.patologias || [],
      medicacion: c.medicacion || '',
      // Preferencias (nuevos campos)
      dieta_anterior: c.dieta_anterior || '',
      alimentos_a_evitar: c.alimentos_a_evitar || '',
      datos_interes: c.datos_interes || '',
      consume_alcohol: c.consume_alcohol || '',
      pica_entre_comidas: c.pica_entre_comidas || '',
      apetencias: c.apetencias || [],
      consume_lacteos: c.consume_lacteos,
      proteinas_preferidas: c.proteinas_preferidas || [],
      notas_proteinas: c.notas_proteinas || '',
      consume_verduras: c.consume_verduras || '',
      carbohidratos_preferidos: c.carbohidratos_preferidos || [],
      frutos_secos_preferidos: c.frutos_secos_preferidos || '',
      contorno_abdominal_1: c.contorno_abdominal_1 || null,
      contorno_abdominal_2: c.contorno_abdominal_2 || null,
      contorno_abdominal_3: c.contorno_abdominal_3 || null,
      consume_bebidas_azucaradas: c.consume_bebidas_azucaradas || '',
      bebidas_vegetales_preferidas: c.bebidas_vegetales_preferidas || [],
      tipo_dieta:                   c.tipo_dieta || 'no',
      imc,
      imc_categoria: imc_cat
    },
    calculos: {
      tmb: Math.round(tmb),
      tdee: Math.round(tdee),
      imc,
      imc_categoria: imc_cat,
      objetivo: {
        calorias: cal_objetivo,
        proteinas_g: proteinas_g,
        carbohidratos_g: carbos_g,
        grasas_g: grasas_g
      },
      distribucion_por_comida: distribucionComidas,
      rangos: {
        calorias: rango(cal_objetivo),
        proteinas: rango(proteinas_g),
        carbohidratos: rango(carbos_g),
        grasas: rango(grasas_g)
      },
      notas_especiales: notasEspeciales,
      alertas
    },
    metadata: {
      id_solicitud: 'PAY-' + Date.now(),
      timestamp: new Date().toISOString()
    },
    es_renovacion: esRenovacion,
    recetas_a_no_repetir: esRenovacion ? await (async () => {
      // Obtener recetas del plan anterior para no repetirlas
      // ⚠️ REEMPLAZA con tu Supabase Anon Key (Project Settings > API > anon public)
      const SUPABASE_URL = 'https://blardvkldwwbhgdmsxhd.supabase.co';
      const SUPABASE_KEY = 'REEMPLAZAR_CON_TU_SUPABASE_ANON_KEY';
      try {
        const res = await this.helpers.httpRequest({
          method: 'GET',
          url: `${SUPABASE_URL}/rest/v1/dietas_generadas?cliente_id=eq.${c.id}&estado=eq.enviada&select=plan_completo&order=created_at.desc&limit=1`,
          headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` }
        });
        const dieta = Array.isArray(res) ? res[0] : res;
        if (!dieta || !dieta.plan_completo) return [];
        const plan = typeof dieta.plan_completo === 'string' ? JSON.parse(dieta.plan_completo) : dieta.plan_completo;
        const nombres = [];
        for (const sem of (plan.semanas || [])) {
          for (const dia of (sem.dias || [])) {
            for (const comida of (dia.comidas || [])) {
              if (comida.nombre) nombres.push(comida.nombre);
            }
          }
        }
        return [...new Set(nombres)];
      } catch(e) { return []; }
    })() : []
  }
}];
